export type AqiLevel = "good" | "moderate" | "unhealthy-sensitive" | "unhealthy" | "hazardous";

export interface Sensor {
  id: string;
  name: string;
  type: "AirBeam" | "Government" | "PurpleAir";
  lat: number;
  lng: number;
  aqi: number;
  pm25: number;
  pm10: number;
  temperature: number;
  humidity: number;
  lastUpdated: string;
  active: boolean;
}

export interface Thresholds {
  min: number;
  low: number;
  middle: number;
  high: number;
  max: number;
}

export const PM25_THRESHOLDS: Thresholds = {
  min: 0,
  low: 12,
  middle: 35,
  high: 55,
  max: 150,
};

export const AQI_COLORS: Record<AqiLevel, string> = {
  good: "#96D788",
  moderate: "#FFD960",
  "unhealthy-sensitive": "#FCA443",
  unhealthy: "#E95F5F",
  hazardous: "#8B5CF6",
};

export function getAqiLevel(aqi: number): AqiLevel {
  if (aqi <= 50) return "good";
  if (aqi <= 100) return "moderate";
  if (aqi <= 150) return "unhealthy-sensitive";
  if (aqi <= 200) return "unhealthy";
  return "hazardous";
}

export function getAqiColor(aqi: number): string {
  return AQI_COLORS[getAqiLevel(aqi)];
}

export function getAqiLabel(aqi: number): string {
  const level = getAqiLevel(aqi);
  const labels: Record<AqiLevel, string> = {
    good: "Good",
    moderate: "Moderate",
    "unhealthy-sensitive": "Unhealthy for Sensitive Groups",
    unhealthy: "Unhealthy",
    hazardous: "Hazardous",
  };
  return labels[level];
}

