"use client";

import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { ChartContainer } from "@/components/ui/chart";
import { Area, AreaChart, Cell, Pie, PieChart } from "recharts";
import {
  hourlyAqi,
  hourlyAqiChartConfig,
  sensorTypeData,
  sensorTypeChartConfig,
  sensors,
  getAqiColor,
  getAqiLabel,
} from "../data";

function AqiTrendChart() {
  return (
    <ChartContainer
      config={hourlyAqiChartConfig}
      className="aspect-auto h-8 w-full"
    >
      <AreaChart data={hourlyAqi} margin={{ left: 4, right: 4, top: 4 }}>
        <defs>
          <linearGradient id="aqiGradient" x1="0" y1="0" x2="0" y2="1">
            <stop
              offset="0%"
              stopColor="var(--color-aqi)"
              stopOpacity={0.4}
            />
            <stop
              offset="100%"
              stopColor="var(--color-aqi)"
              stopOpacity={0}
            />
          </linearGradient>
        </defs>
        <Area
          type="natural"
          dataKey="aqi"
          stroke="var(--color-aqi)"
          strokeWidth={1.5}
          fill="url(#aqiGradient)"
        />
      </AreaChart>
    </ChartContainer>
  );
}

export function AqiOverviewCard() {
  const avgAqi = Math.round(
    sensors.reduce((sum, s) => sum + s.aqi, 0) / sensors.length,
  );
  const color = getAqiColor(avgAqi);
  const label = getAqiLabel(avgAqi);

  return (
    <Card className="bg-card/70 absolute top-4 left-4 z-10 w-60 backdrop-blur-sm">
      <CardHeader>
        <div>
          <p className="text-muted-foreground pb-1 text-[10px] tracking-wider uppercase">
            Average AQI
          </p>
          <div className="flex items-end gap-2">
            <p className="text-3xl leading-none font-semibold">{avgAqi}</p>
            <span
              className="mb-0.5 rounded-full px-2 py-0.5 text-[10px] font-medium text-white"
              style={{ backgroundColor: color }}
            >
              {label}
            </span>
          </div>
        </div>
      </CardHeader>

      <CardContent>
        <AqiTrendChart />
        <p className="text-muted-foreground mt-1.5 text-[10px]">
          Hourly trend today
        </p>

        <div className="border-border/60 mt-4 border-t pt-4">
          <p className="text-muted-foreground text-[10px] tracking-wider uppercase">
            Active sensors by type
          </p>

          <ChartContainer
            config={sensorTypeChartConfig}
            className="mx-auto mt-3 aspect-square h-32 w-32"
          >
            <PieChart>
              <Pie
                data={sensorTypeData}
                dataKey="value"
                nameKey="name"
                innerRadius={32}
                outerRadius={52}
                strokeWidth={2}
              >
                {sensorTypeData.map((entry) => (
                  <Cell key={entry.name} fill={entry.fill} />
                ))}
              </Pie>
            </PieChart>
          </ChartContainer>

          <div className="mt-3 grid grid-cols-3 gap-2">
            {sensorTypeData.map((type) => (
              <div key={type.name} className="text-center">
                <p className="text-muted-foreground flex items-center justify-center gap-1.5 text-[10px] tracking-wide uppercase">
                  <span
                    className="size-2 rounded-full"
                    style={{ backgroundColor: type.fill }}
                  />
                  {type.name}
                </p>
                <p className="text-foreground mt-1 leading-none font-medium tabular-nums">
                  {type.value}
                </p>
              </div>
            ))}
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { type Sensor, getAqiColor, getAqiLabel, PM25_THRESHOLDS } from "../data";

interface SensorDetailCardProps {
  sensor: Sensor | null;
}

function ReadingRow({
  label,
  value,
  unit,
  max,
}: {
  label: string;
  value: number;
  unit: string;
  max: number;
}) {
  const pct = Math.min((value / max) * 100, 100);
  const barColor =
    pct < 40
      ? "bg-emerald-500/85"
      : pct < 70
        ? "bg-amber-400/85"
        : "bg-red-500/85";

  return (
    <div className="space-y-1.5">
      <div className="flex items-center justify-between text-xs">
        <span className="text-foreground/90">{label}</span>
        <span className="text-foreground font-medium tabular-nums">
          {value}{" "}
          <span className="text-muted-foreground text-[10px]">{unit}</span>
        </span>
      </div>
      <div className="bg-muted h-1 rounded-full">
        <div
          className={`h-full rounded-full ${barColor}`}
          style={{ width: `${pct}%` }}
        />
      </div>
    </div>
  );
}

export function SensorDetailCard({ sensor }: SensorDetailCardProps) {
  if (!sensor) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="text-sm font-medium">Sensor Details</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground text-sm">
            Select a sensor on the map or list to view its details.
          </p>
        </CardContent>
      </Card>
    );
  }

  const color = getAqiColor(sensor.aqi);
  const label = getAqiLabel(sensor.aqi);

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between">
          <div>
            <CardTitle className="text-sm font-medium">{sensor.name}</CardTitle>
            <p className="text-muted-foreground text-xs">
              {sensor.type} &middot; Updated {sensor.lastUpdated}
            </p>
          </div>
          <div
            className="rounded-full px-2 py-0.5 text-[10px] font-medium text-white"
            style={{ backgroundColor: color }}
          >
            {label}
          </div>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        <div className="flex items-end gap-3">
          <p className="text-4xl leading-none font-semibold tabular-nums">
            {sensor.aqi}
          </p>
          <span className="text-muted-foreground mb-0.5 text-sm">AQI</span>
        </div>

        <div className="border-border/60 space-y-3 border-t pt-4">
          <ReadingRow
            label="PM2.5"
            value={sensor.pm25}
            unit="μg/m³"
            max={PM25_THRESHOLDS.max}
          />
          <ReadingRow
            label="PM10"
            value={sensor.pm10}
            unit="μg/m³"
            max={300}
          />
          <ReadingRow
            label="Temperature"
            value={sensor.temperature}
            unit="°F"
            max={120}
          />
          <ReadingRow
            label="Humidity"
            value={sensor.humidity}
            unit="%"
            max={100}
          />
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { type Sensor, getAqiColor, getAqiLabel } from "../data";

interface SensorListCardProps {
  sensors: Sensor[];
  selectedId: string | null;
  onSelect: (id: string) => void;
}

export function SensorListCard({
  sensors,
  selectedId,
  onSelect,
}: SensorListCardProps) {
  const sorted = [...sensors].sort((a, b) => b.aqi - a.aqi);

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-sm font-medium">Active Sensors</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="text-muted-foreground mb-2 flex items-center justify-between text-[11px] tracking-wider uppercase">
          <span>Sensor</span>
          <span>AQI</span>
        </div>
        <div className="space-y-1">
          {sorted.map((sensor) => {
            const color = getAqiColor(sensor.aqi);
            const isSelected = sensor.id === selectedId;
            return (
              <button
                key={sensor.id}
                onClick={() => onSelect(sensor.id)}
                className={`flex w-full items-center gap-2.5 rounded-md px-2 py-2 text-left transition-colors ${
                  isSelected
                    ? "bg-accent"
                    : "hover:bg-accent/50"
                }`}
              >
                <span
                  className="size-2.5 shrink-0 rounded-full"
                  style={{ backgroundColor: color }}
                />
                <div className="min-w-0 flex-1">
                  <p className="text-foreground/90 truncate text-xs">
                    {sensor.name}
                  </p>
                  <p className="text-muted-foreground text-[10px]">
                    {sensor.type} &middot; {sensor.lastUpdated}
                  </p>
                </div>
                <div className="text-right">
                  <p
                    className="text-xs font-semibold tabular-nums"
                    style={{ color }}
                  >
                    {sensor.aqi}
                  </p>
                  <p className="text-muted-foreground max-w-16 truncate text-[9px]">
                    {getAqiLabel(sensor.aqi)}
                  </p>
                </div>
              </button>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
}

